INSERT INTO gda_bd_activities (
  activity_type, opp_id, contact_name, contact_org,
  notes, logged_by, follow_up_date, outcome, logged_at
) VALUES ($1, $2::integer, $3, $4, $5, $6, $7::date, $8, NOW())
RETURNING id, activity_type, logged_at;

CREATE TABLE IF NOT EXISTS gda_bd_activities (
  id SERIAL PRIMARY KEY,
  activity_type VARCHAR(50) NOT NULL DEFAULT 'note',
  opp_id INTEGER REFERENCES gda_opportunity_tracker(id) ON DELETE SET NULL,
  contact_name TEXT,
  contact_org TEXT,
  notes TEXT,
  logged_by TEXT DEFAULT 'Shawn',
  follow_up_date DATE,
  outcome TEXT,
  logged_at TIMESTAMPTZ DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_bd_act_opp ON gda_bd_activities(opp_id);
CREATE INDEX IF NOT EXISTS idx_bd_act_date ON gda_bd_activities(logged_at DESC);
SELECT 'gda_bd_activities ready' AS status;
